import { randomUUID } from "node:crypto";

export function nowMs(): number {
  return Date.now();
}

export function nowSec(): number {
  return Math.floor(Date.now() / 1000);
}

export function genId(prefix: string): string {
  return `${prefix}_${randomUUID().replace(/-/g, "").slice(0, 12)}`;
}

export function extractRequestBody(params?: Record<string, unknown>): Record<string, unknown> {
  if (!params || typeof params !== "object") {
    return {};
  }
  const request = params.request;
  if (request && typeof request === "object" && !Array.isArray(request)) {
    return request as Record<string, unknown>;
  }
  return params;
}

export function pickParam<T = unknown>(
  body: Record<string, unknown>,
  keys: string[],
): T | undefined {
  for (const key of keys) {
    if (key in body) {
      return body[key] as T;
    }
  }
  return undefined;
}

export function requireParam<T = unknown>(
  body: Record<string, unknown>,
  keys: string[],
  name: string,
): T {
  const value = pickParam<T>(body, keys);
  if (value === undefined || value === null || value === "") {
    throw new Error(`${name} required`);
  }
  return value;
}

export function setByPath(target: Record<string, unknown>, path: string, value: unknown): void {
  const parts = path.split(".").filter(Boolean);
  if (parts.length === 0) {
    throw new Error("path required");
  }
  let cur: Record<string, unknown> = target;
  for (let i = 0; i < parts.length - 1; i++) {
    const key = parts[i];
    const next = cur[key];
    if (!next || typeof next !== "object" || Array.isArray(next)) {
      cur[key] = {};
    }
    cur = cur[key] as Record<string, unknown>;
  }
  cur[parts[parts.length - 1]] = value;
}

export function getByPath(target: Record<string, unknown>, path?: string): unknown {
  if (!path) {
    return target;
  }
  const parts = path.split(".").filter(Boolean);
  let cur: unknown = target;
  for (const part of parts) {
    if (!cur || typeof cur !== "object" || !(part in (cur as Record<string, unknown>))) {
      throw new Error(`Config path not found: ${path}`);
    }
    cur = (cur as Record<string, unknown>)[part];
  }
  return cur;
}

export function deleteByPath(target: Record<string, unknown>, path: string): void {
  const parts = path.split(".").filter(Boolean);
  if (parts.length === 0) {
    return;
  }
  let cur: Record<string, unknown> = target;
  for (let i = 0; i < parts.length - 1; i++) {
    const key = parts[i];
    const next = cur[key];
    if (!next || typeof next !== "object" || Array.isArray(next)) {
      return;
    }
    cur = next as Record<string, unknown>;
  }
  delete cur[parts[parts.length - 1]];
}

